const SERVICES = [
    ["AI Consulting 1-1", "Private 90-min strategy session — custom roadmap delivered in 48h."],
    ["Custom AI Websites", "Next.js sites built to convert — shipped in under 10 days."],
    ["Custom Dashboards", "Live revenue intelligence — KPI tracking, forecasting, CRM sync."],
    ["PDF to Video (Multi-Language)", "Transform documents into narrated videos in 25+ languages."],
    ["Custom Photo & Video Ads", "AI-generated ads — print, social, video. 10× faster than agencies."],
];

// Inline styles used for radial-gradient values — Tailwind v4 arbitrary bg syntax
// does not reliably process complex multi-stop radial gradients at build time.
function Globe() {
    return (
        <div style={{ position: 'relative', width: 380, height: 380, flexShrink: 0 }}>
            {/* Outer glow halo */}
            <div style={{ position: 'absolute', inset: -32, borderRadius: '50%', background: 'radial-gradient(circle, rgba(6,182,212,0.08) 0%, transparent 70%)', filter: 'blur(28px)', pointerEvents: 'none' }} />
            {/* Orbit ring 1 */}
            <div className="animate-slow-spin" style={{ position: 'absolute', inset: 0, borderRadius: '50%', border: '1px solid rgba(6,182,212,0.18)' }} />
            {/* Orbit ring 2 (counter-spin) */}
            <div style={{ position: 'absolute', inset: 20, borderRadius: '50%', border: '1px solid rgba(139,92,246,0.13)', animation: 'slow-spin 55s linear infinite reverse' }} />
            {/* Globe body */}
            <div style={{ position: 'absolute', inset: 44, borderRadius: '50%', background: 'radial-gradient(circle at 35% 30%, #0e2d3a 0%, #050b10 65%)', border: '1px solid rgba(6,182,212,0.28)', boxShadow: '0 0 50px rgba(6,182,212,0.14), inset 0 0 50px rgba(0,0,0,0.8)', overflow: 'hidden' }}>
                {/* Continent SVGs */}
                <svg viewBox="0 0 200 200" style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', opacity: 0.5 }}>
                    <ellipse cx="58" cy="68" rx="28" ry="18" fill="#06b6d4" opacity="0.65" transform="rotate(-18 58 68)" />
                    <ellipse cx="138" cy="78" rx="18" ry="32" fill="#06b6d4" opacity="0.55" transform="rotate(22 138 78)" />
                    <ellipse cx="100" cy="138" rx="32" ry="16" fill="#06b6d4" opacity="0.5" transform="rotate(-8 100 138)" />
                    <ellipse cx="42" cy="138" rx="16" ry="10" fill="#06b6d4" opacity="0.6" />
                    <ellipse cx="158" cy="48" rx="12" ry="8" fill="#06b6d4" opacity="0.45" />
                    <line x1="0" x2="200" y1="66" y2="66" stroke="rgba(6,182,212,0.12)" strokeWidth="0.8" />
                    <line x1="0" x2="200" y1="100" y2="100" stroke="rgba(6,182,212,0.16)" strokeWidth="0.8" />
                    <line x1="0" x2="200" y1="134" y2="134" stroke="rgba(6,182,212,0.12)" strokeWidth="0.8" />
                    <line x1="60" x2="60" y1="0" y2="200" stroke="rgba(6,182,212,0.12)" strokeWidth="0.8" />
                    <line x1="100" x2="100" y1="0" y2="200" stroke="rgba(6,182,212,0.16)" strokeWidth="0.8" />
                    <line x1="140" x2="140" y1="0" y2="200" stroke="rgba(6,182,212,0.12)" strokeWidth="0.8" />
                </svg>
                {/* Specular highlight */}
                <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(circle at 35% 30%, rgba(6,182,212,0.18) 0%, transparent 60%)' }} />
            </div>
            {/* Data-point dots */}
            <div className="animate-pulse-slow" style={{ position: 'absolute', top: '22%', left: '30%', width: 13, height: 13, borderRadius: '50%', background: '#06b6d4', boxShadow: '0 0 24px #06b6d4' }} />
            <div className="animate-pulse-slow" style={{ position: 'absolute', top: '68%', left: '22%', width: 9, height: 9, borderRadius: '50%', background: '#06b6d4', boxShadow: '0 0 18px #06b6d4', animationDelay: '0.5s' }} />
            <div className="animate-pulse-slow" style={{ position: 'absolute', top: '52%', left: '68%', width: 11, height: 11, borderRadius: '50%', background: '#06b6d4', boxShadow: '0 0 20px #06b6d4', animationDelay: '1s' }} />
            <div className="animate-pulse-slow" style={{ position: 'absolute', top: '28%', left: '68%', width: 7, height: 7, borderRadius: '50%', background: '#8b5cf6', boxShadow: '0 0 14px #8b5cf6', animationDelay: '1.5s' }} />
        </div>
    );
}

export default function HeroSection() {
    return (
        <section className="relative min-h-screen flex items-center pt-20 pb-16 px-6 lg:px-10 overflow-hidden">
            {/* Grid background */}
            <div className="grid-bg absolute inset-0 opacity-40 pointer-events-none" />

            <div className="max-w-7xl mx-auto w-full grid lg:grid-cols-2 gap-12 lg:gap-16 items-center relative z-10">

                {/* Left: Copy + Services (desktop: column 1) */}
                <div>
                    <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full border border-white/10 mb-6">
                        <span className="text-[10px] font-bold tracking-[0.18em] text-zinc-500 uppercase">
                            AI Strategy Group
                        </span>
                    </div>

                    <h1 className="text-4xl sm:text-5xl lg:text-[60px] font-extrabold tracking-[-0.04em] leading-[1.05] mb-3"
                        style={{ background: 'linear-gradient(160deg, #fff 40%, #52525b 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text' }}>
                        BOWEN AI<br />STRATEGY GROUP
                    </h1>

                    <p className="text-lg font-medium mb-8 tracking-[-0.01em]" style={{ color: '#06b6d4' }}>
                        How can we help your business?
                    </p>

                    {/* Numbered service list */}
                    <div className="flex flex-col gap-2 mb-9">
                        {SERVICES.map(([title, desc], i) => (
                            <div
                                key={title}
                                className="flex gap-3.5 items-start p-3 px-4 rounded-[10px] border border-white/[0.06] hover:border-white/[0.15] transition-all cursor-default"
                                style={{ background: 'rgba(255,255,255,0.02)' }}
                            >
                                <span className="mono text-[11px] font-bold shrink-0 mt-0.5" style={{ color: '#06b6d4' }}>
                                    {String(i + 1).padStart(2, "0")}
                                </span>
                                <div>
                                    <div className="text-[13px] font-semibold text-white mb-0.5">{title}</div>
                                    <div className="text-[11px] text-zinc-500 leading-relaxed">{desc}</div>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="flex gap-3">
                        <a href="#consulting">
                            <button className="btn-primary text-[13px] px-7 py-3.5 rounded-[10px]">
                                Book a Free Call →
                            </button>
                        </a>
                        <a href="#showcase">
                            <button className="px-6 py-3.5 rounded-[10px] text-[13px] font-semibold text-zinc-400 border border-white/10 hover:border-white/20 hover:text-white transition-all"
                                style={{ background: 'transparent' }}>
                                See Showcase
                            </button>
                        </a>
                    </div>
                </div>

                {/* Right: Globe + badge (desktop: column 2) */}
                <div className="flex flex-col items-center gap-8">
                    <Globe />
                    <div className="badge-live">Systems Online</div>
                </div>

            </div>
        </section>
    );
}
